UPDATE essay_drafts
SET body = #{body}, save_revision = save_revision + 1, client_updated_at = CURRENT_TIMESTAMP, auto_saved_at = CURRENT_TIMESTAMP
WHERE question_id = #{questionId}

UPDATE essay_questions
SET question_text = #{prompt}, max_length = #{maxLength}
WHERE id = #{id} AND workspace_id = #{workspaceId}
